// Writes the per-season stat-priority rationales from scripts/season-editorial.mjs
// into data/bis/<class>-<spec>-pvp-s<N>.json.
//
// The derived season lists are generated by build-pvp-seasons.mjs, which reads
// the same editorial module — this script exists so the prose can be revised
// without re-running that build (it needs the network and the item database).
// Idempotent: run it as often as you like.
//
// Run:  node scripts/apply-season-editorial.mjs

import { readFile, writeFile } from "node:fs/promises";
import { existsSync } from "node:fs";
import path from "node:path";
import { SEASON_EDITORIAL } from "./season-editorial.mjs";

const BIS_DIR = path.join(process.cwd(), "data", "bis");
const SEASONS = [1, 3, 4];

// Guard rails for prose that is written once and then rendered on 72 pages.
const MIN_WORDS = 30;
const MAX_WORDS = 110;

const words = (s) => s.trim().split(/\s+/).filter(Boolean).length;

async function main() {
  const problems = [];
  let written = 0;

  for (const [key, bySeason] of Object.entries(SEASON_EDITORIAL)) {
    const [cls, spec] = key.split("/");

    // Three texts for one spec must not collapse into each other — that is
    // the whole reason they are written per season rather than shared.
    const texts = SEASONS.map((s) => bySeason[s] ?? "");
    for (let i = 0; i < texts.length; i++)
      for (let j = i + 1; j < texts.length; j++)
        if (texts[i] && texts[i] === texts[j])
          problems.push(`${key}: S${SEASONS[i]} and S${SEASONS[j]} are identical`);

    for (const season of SEASONS) {
      const text = bySeason[season];
      const file = path.join(BIS_DIR, `${cls}-${spec}-pvp-s${season}.json`);
      if (!existsSync(file)) {
        problems.push(`${key} S${season}: no list file`);
        continue;
      }
      if (!text) {
        problems.push(`${key} S${season}: missing rationale`);
        continue;
      }
      const n = words(text);
      if (n < MIN_WORDS || n > MAX_WORDS)
        problems.push(`${key} S${season}: ${n} words (want ${MIN_WORDS}-${MAX_WORDS})`);

      const list = JSON.parse(await readFile(file, "utf8"));
      list.statPriorityRationale = text;
      await writeFile(file, JSON.stringify(list, null, 1));
      written++;
    }
  }

  console.log(`wrote ${written} season lists`);

  // Cross-spec duplication: two specs sharing a sentence would be the same
  // thin-content failure the per-season split is meant to avoid.
  const seen = new Map();
  for (const [key, bySeason] of Object.entries(SEASON_EDITORIAL))
    for (const season of SEASONS) {
      const t = bySeason[season];
      if (!t) continue;
      if (seen.has(t)) problems.push(`duplicate text: ${key} S${season} == ${seen.get(t)}`);
      else seen.set(t, `${key} S${season}`);
    }

  if (problems.length) {
    console.warn(`\n${problems.length} problem(s):`);
    for (const p of problems) console.warn(`  ${p}`);
    process.exitCode = 1;
  } else {
    console.log("all rationales present, distinct and within length");
  }
}

await main();
